package cloud.alex.writecontentplatform.service.impl;

import cloud.alex.writecontentplatform.model.dto.image.ImageDto;
import cloud.alex.writecontentplatform.service.FileService;
import cn.hutool.core.io.FileUtil;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;

import java.io.File;

import static org.junit.jupiter.api.Assertions.*;

/**
 * @author wangshuhao
 * @date 2026/4/14
 */
@SpringBootTest
class FileServiceImplTest {

    @Autowired
    private FileService fileService;


    /**
     * 上传本地的图片
     */
    @Test
    void uploadImageBytes() {
        byte[] bytes = FileUtil.readBytes(System.getProperty("user.dir") + File.separator + "tmp" + File.separator + "70658_compressed.jpg");
        ImageDto dto = ImageDto.fromBytes(bytes, "image/jpeg");
        String s = fileService.uploadImage(dto, "test");
        System.out.println(s);
        Assertions.assertNotNull(s);
    }

    /**
     * 上传url的图片
     */
    @Test
    void uploadImageUrl() {
        ImageDto dto =
                ImageDto.fromUrl("https://images.pexels.com/photos/34804017/pexels-photo-34804017.jpeg?auto=compress&cs=tinysrgb&h=650&w=940");
        String s = fileService.uploadImage(dto, "test");
        System.out.println(s);
        Assertions.assertNotNull(s);
    }

    /**
     * 上传base64 图片
     */
    @Test
    void uploadImageBase64() {
        ImageDto dto =
                ImageDto.fromDataUrl("data:image/jpeg;base64,");
        String s = fileService.uploadImage(dto, "test");
        System.out.println(s);
        Assertions.assertNotNull(s);
    }
}